class Solution:
    def minEnd(self, n: int, x: int) -> int:
        bits = []
        i = 0
        while x:
            if x & 1:
                bits.append(i)
            x >>= 1
            i += 1

        res = 0
        for b in bits:
            res |= 1 << b

        mask = 0
        for b in bits:
            mask |= 1 << b

        remaining = n - 1
        pos = 0
        while remaining > 0:
            if (res >> pos) & 1 == 0:
                res |= 1 << pos
                remaining -= 1
            pos += 1

        return res

